const id = msg.req?.query?.id;

if (msg.checkChargers) {
    const count = msg.payload && msg.payload[0] ? msg.payload[0].count : 0;

    if (count > 0) {
        msg.statusCode = 400;
        msg.payload = {
            success: false,
            message: `Cannot delete location. It has ${count} charger(s) associated with it.`
        };
        return msg;
    }

    // Proceed with deletion
    msg.topic = `DELETE FROM ocpp_CSGO.Locations WHERE location_id = ?;`;
    msg.payload = [id];
    msg.checkChargers = false;

    // Send back to MySQL node
    node.send(msg);
    return null;
}

// Deletion successful
msg.payload = {
    success: true,
    message: "Location deleted successfully"
};
return msg;

changes.new_function_code:
const status = msg.req.query.status;
const locationId = msg.req.query.locationId || msg.req.query.location_id;

const allowedStatus = ["online", "offline"];

let whereClause = "";
const conditions = [];

if (status) {
    if (!allowedStatus.includes(status)) {
        msg.statusCode = 400;
        msg.payload = {
            success: false,
            message: "Invalid status value. Allowed: online, offline"
        };
        return null; 
    }
    conditions.push(`c.status = '${status}'`);
}

if (locationId) {
    conditions.push(`c.location_id = '${locationId}'`);
}

if (conditions.length > 0) {
    whereClause = `WHERE ${conditions.join(' AND ')}`;
}

msg.topic = `
SELECT 
    c.charger_id AS id,
    c.name AS name,
    c.chargerID AS chargerID,
    c.ocpi_last_update AS time,
    c.status AS status,
    c.type AS type,
    c.location_id AS locationId
FROM ocpp_CSGO.Chargers c
${whereClause}
ORDER BY c.ocpi_last_update DESC;
`;

msg.payload = [];
return msg;

const id = msg.req.query.id;
if (!id || isNaN(id)) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: "Invalid charger id" };
  return msg;
}

// Check if charger has connectors
msg.topic = `SELECT COUNT(*) as count FROM ocpp_CSGO.Connectors WHERE charger_id = ?`;
msg.payload = [Number(id)];
msg.checkConnectors = true;
return msg;

const d = msg.payload;
if (!d.charger_id && !d.chargerId && !d.id) {
  msg.statusCode = 400;
  msg.payload = { success: false, message: "charger_id is required" };
  return [null, msg];
}

// Normalize charger_id
d.charger_id = d.charger_id || d.chargerId || d.id;

msg.data = d;
return [msg, null];

